const rows = $input.all().map(i => i.json);

// Group by model_name
const byModel = {};
for (const row of rows) {
  if (!byModel[row.model_name]) byModel[row.model_name] = [];
  byModel[row.model_name].push(row);
}

const comparisons = [];
for (const [modelName, versions] of Object.entries(byModel)) {
  if (versions.length < 2) continue;

  // Sort by version, assume last two are A (current) and B (challenger)
  versions.sort((a, b) => (a.model_version || '').localeCompare(b.model_version || ''));
  const modelA = versions[versions.length - 2];
  const modelB = versions[versions.length - 1];

  const accDiff = (modelB.accuracy || 0) - (modelA.accuracy || 0);
  const maeDiff = (modelA.mae || 0) - (modelB.mae || 0); // lower is better
  const minSamples = 50;
  const sufficientData = modelA.total >= minSamples && modelB.total >= minSamples;

  // Model B is better if accuracy is higher AND mae is lower (or equal)
  const bIsBetter = sufficientData && accDiff > 2 && maeDiff >= 0;

  comparisons.push({
    modelName,
    modelA: { version: modelA.model_version, accuracy: modelA.accuracy, mae: modelA.mae, rmse: modelA.rmse, total: modelA.total },
    modelB: { version: modelB.model_version, accuracy: modelB.accuracy, mae: modelB.mae, rmse: modelB.rmse, total: modelB.total },
    accDiff: accDiff.toFixed(2),
    maeDiff: maeDiff.toFixed(4),
    bIsBetter,
    sufficientData
  });
}

return [{ json: { comparisons, hasPromotion: comparisons.some(c => c.bIsBetter) } }];

const comparisons = $input.first().json.comparisons;
const toPromote = comparisons.filter(c => c.bIsBetter);
return toPromote.map(c => ({ json: c }));

const comp = $('Get Promotions').first().json;
const promoteResult = $input.first().json;

const message = `MODEL PROMOTION\n\n` +
  `Model: ${comp.modelName}\n` +
  `Promoted: ${comp.modelB.version} (was ${comp.modelA.version})\n\n` +
  `Model A (old): Accuracy ${comp.modelA.accuracy}%, MAE ${comp.modelA.mae}, ${comp.modelA.total} samples\n` +
  `Model B (new): Accuracy ${comp.modelB.accuracy}%, MAE ${comp.modelB.mae}, ${comp.modelB.total} samples\n\n` +
  `Accuracy diff: +${comp.accDiff}%\n` +
  `MAE improvement: ${comp.maeDiff}\n\n` +
  `Status: ${promoteResult.success ? 'SUCCESS' : 'FAILED — ' + (promoteResult.error || 'unknown')}`;

return [{ json: { message, chatId: process.env.TELEGRAM_ALERT_CHAT_ID || '' } }];

const comparisons = $input.first().json.comparisons;

let message = `MODEL A/B REPORT (No Promotions)\n\n`;
for (const c of comparisons) {
  message += `${c.modelName}:\n`;
  message += `  A (${c.modelA.version}): ${c.modelA.accuracy}% acc, ${c.modelA.mae} MAE\n`;
  message += `  B (${c.modelB.version}): ${c.modelB.accuracy}% acc, ${c.modelB.mae} MAE\n`;
  message += `  Sufficient data: ${c.sufficientData ? 'Yes' : 'No'}\n\n`;
}
if (comparisons.length === 0) message += 'No models with multiple versions to compare.';

return [{ json: { message, chatId: process.env.TELEGRAM_ALERT_CHAT_ID || '' } }];
